let parsed = {};
let rawText = '';

try {
  rawText =
    $json.content?.parts?.[0]?.text ||
    $json.candidates?.[0]?.content?.parts?.[0]?.text ||
    $json.text ||
    '';

  // Remove code fences if present
  const cleaned = typeof rawText === 'string'
    ? rawText.replace(/```json|```/gi, '').trim()
    : '';

  // Try direct parse first (best case)
  try {
    parsed = JSON.parse(cleaned);
  } catch {
    // Fallback: extract JSON block (greedy to capture full object)
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      parsed = JSON.parse(match[0]);
    }
  }

} catch (error) {
  parsed = {
    error: 'Parsing failed',
    raw_output: rawText
  };
}

return {
  json: {
    email: parsed.subject ?? '',
    is_suspicious: parsed.phishing_likely ?? false,
    summary: parsed.summary ?? '',
    reasons: parsed.reasons ?? []
  }
};
